import { ActionIcon, Menu, NumberInput, Switch } from "@mantine/core";
import { Settings } from "lucide-react";
import { globalState } from "../../context/GlobalState";
import { Horizontal, Vertical } from "../../utils/ComponentToolbox";
import { DarkModeButton } from "../DarkModeButton";
import { LanguageButton } from "../LanguageButton";

const toggleWrap = () => (globalState.layout.wrap.value = !globalState.layout.wrap.value);

const onChangeColumnCount = (value: number | string) =>
	void (typeof value === "number" && (globalState.layout.columnCount.value = value));

const onChangeRowHeight = (value: number | string) =>
	void (typeof value === "number" && (globalState.layout.rowHeight.value = value));

export const SettingsMenu = () => (
	<Menu position="bottom-end">
		<Menu.Target>
			<ActionIcon variant="transparent">
				<Settings />
			</ActionIcon>
		</Menu.Target>
		<Menu.Dropdown p="sm">
			<Vertical gap={8}>
				<Horizontal justifyContent="space-between">
					<Switch label="Wrap" labelPosition="left" checked={globalState.layout.wrap.value} onChange={toggleWrap} />
					<Horizontal style={{ alignSelf: "flex-end" }} gap={16}>
						<LanguageButton useTransition />
						<DarkModeButton useTransition />
					</Horizontal>
				</Horizontal>
				<Horizontal gap={16}>
					<NumberInput
						label="Column count"
						min={1}
						max={5}
						value={globalState.layout.columnCount.value}
						onChange={onChangeColumnCount}
					/>
					<NumberInput
						label="Row height"
						min={215}
						max={400}
						value={globalState.layout.rowHeight.value}
						onChange={onChangeRowHeight}
					/>
				</Horizontal>
			</Vertical>
		</Menu.Dropdown>
	</Menu>
);
